#!/usr/bin/env node
// ============================================================================
// Guard: the `functions` and `web` packages each carry their own copy of the
// project dataset, because they are separate npm packages and cannot import
// across the boundary.
//
//   web/src/data/projectsEnhanced.ts   ─┐ curated seed (HAND-MAINTAINED)
//   functions/src/projectsData.ts      ─┘
//
//   web/src/data/projectsLive.ts       ─┐ live crawl (auto-generated by
//   functions/src/projectsLive.ts      ─┘ fetch-live-projects.mjs — both)
//
// The live pair is written by the crawler, so it stays in sync on its own.
// The curated pair is NOT: its only guard used to be a comment saying "keep in
// sync". If the two drift, project IDs diverge between tiers — the AI tools,
// Chroma vectors, and cached insights are all keyed on those IDs, so a drifted
// ID means a project that silently cannot be matched or ranked. Nothing crashes;
// results just quietly go missing.
//
// This script turns that comment into an enforced invariant.
//
// Run: node script/check-data-sync.mjs   (exit 1 on drift)
// ============================================================================

import { readFileSync } from 'node:fs'
import { resolve, dirname } from 'node:path'
import { fileURLToPath } from 'node:url'

const ROOT = resolve(dirname(fileURLToPath(import.meta.url)), '..')

/** Pull an exported array literal out of a TS source file (data-only literals). */
function extractArray(relPath, exportName) {
  const src = readFileSync(resolve(ROOT, relPath), 'utf8')
  const re = new RegExp(`export const ${exportName}[^=]*= (\\[[\\s\\S]*?\\n\\])`)
  const match = src.match(re)
  if (!match) throw new Error(`Could not locate "${exportName}" in ${relPath}`)
  return eval(match[1]) // plain object/array literals only — no expressions
}

/** Compare two datasets by id, reporting exactly what diverged. */
function compare(label, a, b, aPath, bPath) {
  const problems = []

  const idsA = a.map((p) => p.id)
  const idsB = b.map((p) => p.id)
  const setB = new Set(idsB)
  const setA = new Set(idsA)

  const onlyA = idsA.filter((id) => !setB.has(id))
  const onlyB = idsB.filter((id) => !setA.has(id))

  if (onlyA.length) problems.push(`  only in ${aPath}: ${onlyA.join(', ')}`)
  if (onlyB.length) problems.push(`  only in ${bPath}: ${onlyB.join(', ')}`)

  // Same ids present on both sides — do the records themselves agree?
  const byB = new Map(b.map((p) => [p.id, p]))
  for (const rec of a) {
    const other = byB.get(rec.id)
    if (!other) continue
    if (JSON.stringify(rec) !== JSON.stringify(other)) {
      problems.push(`  "${rec.id}" differs between the two copies`)
    }
  }

  if (problems.length) {
    console.error(`✗ ${label} — ${a.length} vs ${b.length} records, DRIFTED:`)
    for (const p of problems.slice(0, 20)) console.error(p)
    if (problems.length > 20) console.error(`  …and ${problems.length - 20} more`)
    return false
  }

  console.log(`✓ ${label} — ${a.length} records, in sync`)
  return true
}

const WEB_CURATED = 'web/src/data/projectsEnhanced.ts'
const FN_CURATED = 'functions/src/projectsData.ts'
const WEB_LIVE = 'web/src/data/projectsLive.ts'
const FN_LIVE = 'functions/src/projectsLive.ts'

const ok = [
  compare(
    'curated seed',
    extractArray(WEB_CURATED, 'curatedProjects'),
    extractArray(FN_CURATED, 'curatedProjects'),
    WEB_CURATED,
    FN_CURATED,
  ),
  compare(
    'live crawl',
    extractArray(WEB_LIVE, 'liveProjects'),
    extractArray(FN_LIVE, 'liveProjects'),
    WEB_LIVE,
    FN_LIVE,
  ),
].every(Boolean)

if (!ok) {
  console.error(
    `\nThe backend and frontend datasets disagree.\n` +
      `Project IDs are the join key for AI tools, Chroma vectors and cached insights,\n` +
      `so drift here makes projects silently unmatchable rather than throwing.\n\n` +
      `Fix: copy the curated array from ${WEB_CURATED} into ${FN_CURATED}\n` +
      `(web is the source of truth), or re-run: node script/fetch-live-projects.mjs\n`,
  )
  process.exit(1)
}

console.log('\nDatasets are in sync across web/ and functions/.')
